const checkpointNode = $input.first().json?.CheckpointLoaderSimple;
const availableCheckpoints = Array.isArray(checkpointNode?.input?.required?.ckpt_name?.[0])
  ? checkpointNode.input.required.ckpt_name[0]
  : [];
const request = $('Webhook').first().json?.body ?? $('Webhook').first().json ?? {};
const promptText = typeof request.prompt === 'string' && request.prompt.trim()
  ? request.prompt.trim()
  : 'a studio product photo of a red apple on a table';
const negativePrompt = typeof request.negative_prompt === 'string' && request.negative_prompt.trim()
  ? request.negative_prompt.trim()
  : 'blurry, low quality, distorted';
const requestedCheckpoint = typeof request.checkpoint === 'string' && request.checkpoint.trim()
  ? request.checkpoint.trim()
  : (availableCheckpoints.find((name) => /sd.?1\.5|v1-5/i.test(name)) ?? 'v1-5-pruned-emaonly.safetensors');
const seed = Number.isFinite(Number(request.seed)) ? Number(request.seed) : 1;
const steps = Number.isFinite(Number(request.steps)) ? Number(request.steps) : 12;
const cfg = Number.isFinite(Number(request.cfg)) ? Number(request.cfg) : 7;
const width = Number.isFinite(Number(request.width)) ? Number(request.width) : 512;
const height = Number.isFinite(Number(request.height)) ? Number(request.height) : 512;
const samplerName = typeof request.sampler_name === 'string' && request.sampler_name.trim()
  ? request.sampler_name.trim()
  : 'euler';
const scheduler = typeof request.scheduler === 'string' && request.scheduler.trim()
  ? request.scheduler.trim()
  : 'normal';
const clientId = typeof request.client_id === 'string' && request.client_id.trim()
  ? request.client_id.trim()
  : 'prototype-local-sd15';
const comfyuiBaseUrl = typeof request.comfyuiBaseUrl === 'string' && request.comfyuiBaseUrl.trim()
  ? request.comfyuiBaseUrl.trim().replace(/\/$/, '')
  : 'http://comfyui:8188';
const minioPublicBaseUrl = typeof request.minioPublicBaseUrl === 'string' && request.minioPublicBaseUrl.trim()
  ? request.minioPublicBaseUrl.trim().replace(/\/$/, '')
  : 'http://127.0.0.1:9010';
const uniqueSuffix = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
const artifactFileName = `prototype-sd15-${uniqueSuffix}.png`;
const outputDir = '/home/node/.n8n-files/prototype-comfyui';
const outputPath = `${outputDir}/${artifactFileName}`;

return [{
  json: {
    comfyui_base_url: comfyuiBaseUrl,
    minio_public_base_url: minioPublicBaseUrl,
    requestedCheckpoint,
    availableCheckpoints,
    checkpointCount: availableCheckpoints.length,
    prompt: promptText,
    negativePrompt,
    width,
    height,
    steps,
    cfg,
    samplerName,
    scheduler,
    clientId,
    bucket_name: 'artifacts',
    folder_key: 'prototype-comfyui',
    artifact_file_name: artifactFileName,
    object_key: `prototype-comfyui/${artifactFileName}`,
    output_dir: outputDir,
    output_path: outputPath,
    poll_delay_seconds: Number.isFinite(Number(request.poll_delay_seconds)) ? Number(request.poll_delay_seconds) : 10,
    max_poll_attempts: Number.isFinite(Number(request.max_poll_attempts)) ? Number(request.max_poll_attempts) : 30,
    comfyPayload: {
      client_id: clientId,
      prompt: {
        '3': {
          class_type: 'CheckpointLoaderSimple',
          inputs: {
            ckpt_name: requestedCheckpoint
          }
        },
        '4': {
          class_type: 'CLIPTextEncode',
          inputs: {
            text: promptText,
            clip: ['3', 1]
          }
        },
        '5': {
          class_type: 'CLIPTextEncode',
          inputs: {
            text: negativePrompt,
            clip: ['3', 1]
          }
        },
        '6': {
          class_type: 'EmptyLatentImage',
          inputs: {
            width,
            height,
            batch_size: 1
          }
        },
        '7': {
          class_type: 'KSampler',
          inputs: {
            model: ['3', 0],
            seed,
            steps,
            cfg,
            sampler_name: samplerName,
            scheduler,
            positive: ['4', 0],
            negative: ['5', 0],
            latent_image: ['6', 0],
            denoise: 1
          }
        },
        '8': {
          class_type: 'VAEDecode',
          inputs: {
            samples: ['7', 0],
            vae: ['3', 2]
          }
        },
        '9': {
          class_type: 'SaveImage',
          inputs: {
            images: ['8', 0],
            filename_prefix: 'prototype_sd15'
          }
        }
      }
    }
  }
}];

const state = $input.first().json;
const env = [
  `COMFYUI_BASE_URL=${JSON.stringify(state.comfyui_base_url || 'http://comfyui:8188')}`,
  `PROMPT_ID=${JSON.stringify(state.promptId)}`,
  `OUTPUT_PATH=${JSON.stringify(state.output_path)}`,
  `POLL_DELAY_SECONDS=${JSON.stringify(String(state.poll_delay_seconds))}`,
  `MAX_POLL_ATTEMPTS=${JSON.stringify(String(state.max_poll_attempts))}`
].join(' ');

const script = `node - <<'NODE'
const fs = require('fs');
const { setTimeout: sleep } = require('timers/promises');

const baseUrl = process.env.COMFYUI_BASE_URL || 'http://comfyui:8188';
const promptId = process.env.PROMPT_ID;
const outputPath = process.env.OUTPUT_PATH;
const pollDelayMs = Number(process.env.POLL_DELAY_SECONDS || '10') * 1000;
const maxAttempts = Number(process.env.MAX_POLL_ATTEMPTS || '30');

async function main() {
  fs.mkdirSync(require('path').dirname(outputPath), { recursive: true });
  for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
    const historyResponse = await fetch(baseUrl + '/history/' + promptId);
    if (!historyResponse.ok) {
      throw new Error('Failed to fetch history: ' + historyResponse.status);
    }
    const history = await historyResponse.json();
    const entry = history[promptId];
    const completed = entry?.status?.completed === true;
    const image = entry?.outputs?.['9']?.images?.[0] || null;

    if (completed && image) {
      const viewUrl = new URL(baseUrl + '/view');
      viewUrl.searchParams.set('filename', image.filename);
      viewUrl.searchParams.set('subfolder', image.subfolder || '');
      viewUrl.searchParams.set('type', image.type || 'output');
      const fileResponse = await fetch(viewUrl);
      if (!fileResponse.ok) {
        throw new Error('Failed to download image: ' + fileResponse.status);
      }
      const buffer = Buffer.from(await fileResponse.arrayBuffer());
      fs.writeFileSync(outputPath, buffer);
      console.log(JSON.stringify({
        promptId,
        pollAttempt: attempt,
        filename: image.filename,
        subfolder: image.subfolder || '',
        type: image.type || 'output',
        outputPath,
        bytes: buffer.length
      }));
      return;
    }

    if (completed && !image) {
      throw new Error('Prompt completed without image output');
    }

    await sleep(pollDelayMs);
  }

  throw new Error('Timed out waiting for ComfyUI prompt ' + promptId);
}

main().catch((error) => {
  console.error(JSON.stringify({ promptId, error: error.message }));
  process.exit(1);
});
NODE`;

return [{ json: { ...state, poll_command: `${env} ${script}` } }];

const state = $('Prepare Poll Command').first().json;
const stdout = String($input.first().json.stdout || '').trim();
if (!stdout) {
  throw new Error('Poll command did not return download metadata');
}

let metadata;
try {
  metadata = JSON.parse(stdout);
} catch (error) {
  throw new Error(`Invalid poll metadata: ${stdout}`);
}

return [{
  json: {
    ...state,
    promptId: metadata.promptId || state.promptId,
    pollAttempt: metadata.pollAttempt ?? null,
    comfyImageFilename: metadata.filename || null,
    comfySubfolder: metadata.subfolder || '',
    comfyImageType: metadata.type || 'output',
    downloadedBytes: metadata.bytes ?? null,
    output_path: metadata.outputPath || state.output_path
  }
}];

