const crypto = require('crypto');
const fs = require('fs');

const brokerBaseUrl = 'http://broker:8090';
const env = process.env;
const uniqueSuffix = Date.now() + '-' + Math.random().toString(36).slice(2, 10);
const messageKey = env.RAW_MESSAGE_ID || uniqueSuffix;
const sessionId = env.RAW_SESSION_ID || ('adhoc-session-' + uniqueSuffix);
const runId = 'comfy-run-' + messageKey;
const workflowEventId = 'comfy-workflow-event-' + messageKey;
const artifactEventId = 'comfy-artifact-event-' + messageKey;
const failedEventId = 'comfy-failed-event-' + messageKey;
const artifactId = 'comfy-artifact-' + messageKey;
const uri = 's3://' + env.BUCKET_NAME + '/' + env.OBJECT_KEY;
const mimeType = env.OBJECT_KEY.endsWith('.png') ? 'image/png' : 'application/octet-stream';
const checksumSha256 = crypto.createHash('sha256').update(fs.readFileSync(env.OUTPUT_PATH)).digest('hex');
const workflowEventHash = crypto.createHash('sha256').update(workflowEventId + ':' + runId + ':' + uri).digest('hex');
const artifactEventHash = crypto.createHash('sha256').update(artifactEventId + ':' + runId + ':' + uri).digest('hex');

async function post(path, payload) {
  const response = await fetch(brokerBaseUrl + path, {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify(payload),
  });
  const body = await response.text();
  if (!response.ok) {
    throw new Error(path + ' ' + response.status + ' ' + body);
  }
  return body ? JSON.parse(body) : {};
}

async function main() {
  await post('/nodes', {
    node_id: env.NODE_ID,
    node_role: env.NODE_ROLE,
    display_name: env.DISPLAY_NAME,
    metadata_json: { source: 'n8n.workflow', webhook_path: env.WEBHOOK_PATH },
  });
  await post('/sessions', {
    session_id: sessionId,
    node_id: env.NODE_ID,
    surface: env.SURFACE,
    metadata_json: { source: 'n8n.workflow', user_id: env.USER_ID || null, message_id: env.RAW_MESSAGE_ID || null, webhook_path: env.WEBHOOK_PATH },
  });
  await post('/runs', {
    run_id: runId,
    session_id: sessionId,
    run_kind: 'n8n.prototype.comfyui.artifact',
    status: 'started',
    metadata_json: { source: 'n8n.workflow', user_id: env.USER_ID || null, webhook_path: env.WEBHOOK_PATH, prompt_id: env.PROMPT_ID },
  });

  await post('/events', {
    event_id: workflowEventId,
    event_type: 'workflow.completed',
    payload_version: 1,
    node_id: env.NODE_ID,
    session_id: sessionId,
    run_id: runId,
    idempotency_key: env.NODE_ID + ':' + workflowEventId,
    occurred_at: env.OCCURRED_AT,
    payload_json: { prompt: env.PROMPT, requested_checkpoint: env.REQUESTED_CHECKPOINT, prompt_id: env.PROMPT_ID, bucket: env.BUCKET_NAME, object_key: env.OBJECT_KEY, uri: uri, mime_type: mimeType, checksum_sha256: checksumSha256 },
    metadata_json: { source: 'n8n.workflow', webhook_path: env.WEBHOOK_PATH, user_id: env.USER_ID || null },
  });

  await post('/events', {
    event_id: artifactEventId,
    event_type: 'artifact.registered',
    payload_version: 1,
    node_id: env.NODE_ID,
    session_id: sessionId,
    run_id: runId,
    idempotency_key: env.NODE_ID + ':' + artifactEventId,
    source_event_id: workflowEventId,
    source_event_hash: workflowEventHash,
    occurred_at: env.OCCURRED_AT,
    payload_json: { artifact_id: artifactId, artifact_kind: 'blob', storage_backend: 's3', bucket: env.BUCKET_NAME, object_key: env.OBJECT_KEY, uri: uri, mime_type: mimeType, checksum_sha256: checksumSha256 },
    metadata_json: { source: 'n8n.workflow', webhook_path: env.WEBHOOK_PATH, user_id: env.USER_ID || null, prompt_id: env.PROMPT_ID },
  });

  await post('/artifacts', {
    artifact_id: artifactId,
    artifact_kind: 'blob',
    source_event_id: artifactEventId,
    source_event_hash: artifactEventHash,
    storage_backend: 's3',
    uri: uri,
    mime_type: mimeType,
    checksum_sha256: checksumSha256,
    metadata_json: { bucket: env.BUCKET_NAME, object_key: env.OBJECT_KEY, prompt: env.PROMPT, requested_checkpoint: env.REQUESTED_CHECKPOINT, prompt_id: env.PROMPT_ID, run_id: runId, session_id: sessionId, webhook_path: env.WEBHOOK_PATH, user_id: env.USER_ID || null },
  });

  await post('/runs', {
    run_id: runId,
    session_id: sessionId,
    run_kind: 'n8n.prototype.comfyui.artifact',
    status: 'completed',
    metadata_json: { source: 'n8n.workflow', user_id: env.USER_ID || null, webhook_path: env.WEBHOOK_PATH, artifact_id: artifactId, prompt_id: env.PROMPT_ID, uri: uri, mime_type: mimeType, checksum_sha256: checksumSha256 },
  });

  console.log(JSON.stringify({ sessionId: sessionId, runId: runId, workflowEventId: workflowEventId, artifactEventId: artifactEventId, artifactId: artifactId, checksumSha256: checksumSha256, mimeType: mimeType, uri: uri }));
}

main().catch(async (error) => {
  try {
    await post('/events', {
      event_id: failedEventId,
      event_type: 'workflow.failed',
      payload_version: 1,
      node_id: env.NODE_ID,
      session_id: sessionId,
      run_id: runId,
      idempotency_key: env.NODE_ID + ':' + failedEventId,
      occurred_at: env.OCCURRED_AT,
      payload_json: { prompt: env.PROMPT, requested_checkpoint: env.REQUESTED_CHECKPOINT, prompt_id: env.PROMPT_ID, bucket: env.BUCKET_NAME, object_key: env.OBJECT_KEY, error: error.message },
      metadata_json: { source: 'n8n.workflow', webhook_path: env.WEBHOOK_PATH, user_id: env.USER_ID || null },
    });
    await post('/runs', {
      run_id: runId,
      session_id: sessionId,
      run_kind: 'n8n.prototype.comfyui.artifact',
      status: 'failed',
      metadata_json: { source: 'n8n.workflow', webhook_path: env.WEBHOOK_PATH, user_id: env.USER_ID || null, prompt_id: env.PROMPT_ID, error: error.message },
    });
  } catch (_) {}
  console.error(error.message);
  process.exit(1);
});
NODE" }}

